import { useState, useEffect, useCallback } from 'react'

interface GitFile {
  path: string
  status: string
  staged: boolean
}

interface GitStatusData {
  branch: string
  ahead: number
  behind: number
  files: GitFile[]
}

function statusLabel(status: string): string {
  switch (status) {
    case 'M': return 'M'
    case 'A': return 'A'
    case 'D': return 'D'
    case '?': return 'U'
    case 'R': return 'R'
    default: return status
  }
}

function statusColor(status: string): string {
  switch (status) {
    case 'M': return 'text-amber-600'
    case 'A': return 'text-green-600'
    case 'D': return 'text-red-500'
    case '?': return 'text-gray-400'
    default: return 'text-gray-500'
  }
}

export default function GitPanel({ onFileSelect }: { onFileSelect?: (filePath: string) => void }) {
  const [status, setStatus] = useState<GitStatusData | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [loading, setLoading] = useState(true)
  const [commitMsg, setCommitMsg] = useState('')
  const [committing, setCommitting] = useState(false)
  const [staging, setStaging] = useState<string | null>(null)

  const refresh = useCallback(async () => {
    setLoading(true)
    setError(null)
    try {
      const result = await window.api.gitStatus()
      if (result.ok && result.data) {
        setStatus(result.data)
      } else {
        setError(result.error ?? 'Failed to get git status')
        setStatus(null)
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err))
      setStatus(null)
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    refresh()
  }, [refresh])

  useEffect(() => {
    const api = window.api as typeof window.api & { onFsChanged?: (cb: () => void) => () => void }
    if (!api.onFsChanged) return
    let timer: ReturnType<typeof setTimeout> | null = null
    const unsub = api.onFsChanged(() => {
      if (timer) clearTimeout(timer)
      timer = setTimeout(refresh, 500)
    })
    return () => {
      unsub()
      if (timer) clearTimeout(timer)
    }
  }, [refresh])

  const handleStage = useCallback(async (filePath: string) => {
    setStaging(filePath)
    try {
      const result = await window.api.gitStage([filePath])
      if (result.ok) await refresh()
    } finally {
      setStaging(null)
    }
  }, [refresh])

  const handleUnstage = useCallback(async (filePath: string) => {
    setStaging(filePath)
    try {
      const result = await window.api.gitUnstage([filePath])
      if (result.ok) await refresh()
    } finally {
      setStaging(null)
    }
  }, [refresh])

  const handleStageAll = useCallback(async () => {
    if (!status) return
    const paths = status.files.filter(f => !f.staged).map(f => f.path)
    if (paths.length === 0) return
    setStaging('__all__')
    try {
      await window.api.gitStage(paths)
      await refresh()
    } finally {
      setStaging(null)
    }
  }, [status, refresh])

  const handleDiscardAll = useCallback(async () => {
    if (!status) return
    const paths = status.files.filter(f => !f.staged && f.status !== '?').map(f => f.path)
    if (paths.length === 0) return
    setStaging('__discard__')
    try {
      await window.api.gitDiscard(paths)
      await refresh()
    } finally {
      setStaging(null)
    }
  }, [status, refresh])

  const handleCommit = useCallback(async () => {
    if (!commitMsg.trim()) return
    setCommitting(true)
    try {
      const result = await window.api.gitCommit(commitMsg.trim())
      if (result.ok) {
        setCommitMsg('')
        await refresh()
      }
    } finally {
      setCommitting(false)
    }
  }, [commitMsg, refresh])

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full text-gray-400 text-xs">
        Loading...
      </div>
    )
  }

  if (error) {
    return (
      <div className="p-3 text-xs text-gray-400">
        {error}
      </div>
    )
  }

  if (!status) return null

  const staged = status.files.filter(f => f.staged)
  const unstaged = status.files.filter(f => !f.staged && f.status !== '?')
  const untracked = status.files.filter(f => f.status === '?')

  const hasUnstagedOrUntracked = unstaged.length > 0 || untracked.length > 0
  const hasUnstagedChanges = unstaged.length > 0

  return (
    <div className="text-xs flex flex-col h-full">
      <div className="px-3 py-2 border-b border-gray-200 flex items-center gap-2 flex-shrink-0">
        <span className="font-medium text-gray-700">{status.branch}</span>
        {status.ahead > 0 && <span className="text-green-600">↑{status.ahead}</span>}
        {status.behind > 0 && <span className="text-amber-600">↓{status.behind}</span>}
        {hasUnstagedOrUntracked && (
          <div className="ml-auto flex items-center gap-1">
            <button
              onClick={handleStageAll}
              className="rounded p-1 text-gray-400 hover:text-green-600 hover:bg-gray-100 transition-colors"
              disabled={staging !== null}
              title="Stage All"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
              </svg>
            </button>
            {hasUnstagedChanges && (
              <button
                onClick={handleDiscardAll}
                className="rounded p-1 text-gray-400 hover:text-red-500 hover:bg-gray-100 transition-colors"
                disabled={staging !== null}
                title="Discard All Changes"
              >
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M20 12H4" />
                </svg>
              </button>
            )}
          </div>
        )}
        {!hasUnstagedOrUntracked && (
          <button
            onClick={refresh}
            className="ml-auto rounded p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
            title="Refresh"
          >
            <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </button>
        )}
      </div>

      <div className="flex-1 overflow-y-auto min-h-0">
        {staged.length > 0 && (
          <div className="border-b border-gray-200">
            <div className="px-3 py-1.5 text-gray-500 font-medium">Staged Changes ({staged.length})</div>
            {staged.map(f => (
              <div key={f.path} className="px-3 py-1 flex items-center gap-1 hover:bg-gray-100 group" title={f.path}>
                <span className={`w-4 text-center font-mono font-semibold ${statusColor(f.status)}`}>{statusLabel(f.status)}</span>
                <span className="text-gray-700 truncate flex-1 cursor-pointer" onClick={() => onFileSelect?.(f.path)}>{f.path}</span>
                <button
                  onClick={() => handleUnstage(f.path)}
                  disabled={staging !== null}
                  className="rounded p-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-200 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0"
                  title="Unstage"
                >
                  <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M20 12H4" />
                  </svg>
                </button>
              </div>
            ))}
          </div>
        )}

        {unstaged.length > 0 && (
          <div className="border-b border-gray-200">
            <div className="px-3 py-1.5 text-gray-500 font-medium">Changes ({unstaged.length})</div>
            {unstaged.map(f => (
              <div key={f.path} className="px-3 py-1 flex items-center gap-1 hover:bg-gray-100 group" title={f.path}>
                <span className={`w-4 text-center font-mono font-semibold ${statusColor(f.status)}`}>{statusLabel(f.status)}</span>
                <span className="text-gray-700 truncate flex-1 cursor-pointer" onClick={() => onFileSelect?.(f.path)}>{f.path}</span>
                <button
                  onClick={() => handleStage(f.path)}
                  disabled={staging !== null}
                  className="rounded p-0.5 text-gray-400 hover:text-green-600 hover:bg-gray-200 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0"
                  title="Stage"
                >
                  <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
                  </svg>
                </button>
              </div>
            ))}
          </div>
        )}

        {untracked.length > 0 && (
          <div className="border-b border-gray-200">
            <div className="px-3 py-1.5 text-gray-500 font-medium">Untracked ({untracked.length})</div>
            {untracked.map(f => (
              <div key={f.path} className="px-3 py-1 flex items-center gap-1 hover:bg-gray-100 group" title={f.path}>
                <span className={`w-4 text-center font-mono font-semibold ${statusColor(f.status)}`}>U</span>
                <span className="text-gray-700 truncate flex-1 cursor-pointer" onClick={() => onFileSelect?.(f.path)}>{f.path}</span>
                <button
                  onClick={() => handleStage(f.path)}
                  disabled={staging !== null}
                  className="rounded p-0.5 text-gray-400 hover:text-green-600 hover:bg-gray-200 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0"
                  title="Stage"
                >
                  <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
                  </svg>
                </button>
              </div>
            ))}
          </div>
        )}

        {status.files.length === 0 && (
          <div className="px-3 py-4 text-gray-400 text-center">
            No changes
          </div>
        )}
      </div>

      {staged.length > 0 && (
        <div className="border-t border-gray-200 p-2 flex-shrink-0">
          <textarea
            value={commitMsg}
            onChange={e => setCommitMsg(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter' && (e.metaKey || e.ctrlKey) && commitMsg.trim()) {
                e.preventDefault()
                handleCommit()
              }
            }}
            placeholder="Commit message (⌘+Enter)"
            className="w-full resize-none border border-gray-200 rounded px-2 py-1.5 text-xs focus:outline-none focus:border-blue-400"
            rows={2}
            disabled={committing}
          />
          <button
            onClick={handleCommit}
            disabled={!commitMsg.trim() || committing}
            className="w-full mt-1 rounded bg-blue-600 px-3 py-1.5 text-xs font-medium text-white hover:bg-blue-500 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors"
          >
            {committing ? 'Committing...' : 'Commit'}
          </button>
        </div>
      )}
    </div>
  )
}

import FileTree from './FileTree'
import GitPanel from './GitPanel'
import SearchPanel from './SearchPanel'
import type { RightPanelView } from '../hooks/useLayoutStore'

interface RightPanelProps {
  view: RightPanelView
  onViewChange: (view: RightPanelView) => void
  collapsed: boolean
  onToggleCollapse: () => void
  width: number
  onResizeStart: (e: React.MouseEvent) => void
  onFileSelect: (filePath: string, scrollToLine?: number) => void
  onDiffSelect: (filePath: string) => void
}

function FolderIcon({ className }: { className?: string }) {
  return (
    <svg className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
      <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 12.75V12A2.25 2.25 0 014.5 9.75h15A2.25 2.25 0 0121.75 12v.75m-16.5 0h16.5m-16.5 0A2.25 2.25 0 003 15v3.75A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V15a2.25 2.25 0 00-1.5-2.25m-16.5 0V6A2.25 2.25 0 015.25 3.75h5.379a1.5 1.5 0 011.06.44l2.122 2.12a1.5 1.5 0 001.06.44H18.75A2.25 2.25 0 0121 9v.75" />
    </svg>
  )
}

function GitIcon({ className }: { className?: string }) {
  return (
    <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={1.5}>
      <circle cx="12" cy="6" r="2" />
      <circle cx="12" cy="18" r="2" />
      <circle cx="18" cy="12" r="2" />
      <path strokeLinecap="round" d="M12 8v8" />
      <path strokeLinecap="round" d="M16.5 12H14" />
    </svg>
  )
}

function SearchIcon({ className }: { className?: string }) {
  return (
    <svg className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
      <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-5.197-5.197m0 0A7.5 7.5 0 105.196 5.196a7.5 7.5 0 0010.607 10.607z" />
    </svg>
  )
}

export default function RightPanel({
  view,
  onViewChange,
  collapsed,
  onToggleCollapse,
  width,
  onResizeStart,
  onFileSelect,
  onDiffSelect,
}: RightPanelProps) {
  if (collapsed) return null

  return (
    <div
      className="relative border-l border-gray-200 bg-gray-50 flex flex-col overflow-hidden"
      style={{ width: `${width}px` }}
    >
      <div
        className="absolute top-0 left-0 w-1 h-full cursor-col-resize hover:w-1.5 hover:bg-blue-500/30 transition-all z-10"
        onMouseDown={onResizeStart}
      />

      <div className="h-8 flex items-center px-2 border-b border-gray-200 gap-1">
        <button
          onClick={() => onViewChange('files')}
          className={view === 'files' ? 'bg-gray-200 text-gray-900 rounded p-1' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-100 rounded p-1'}
          title="Files"
        >
          <FolderIcon className="w-4 h-4" />
        </button>
        <button
          onClick={() => onViewChange('search')}
          className={view === 'search' ? 'bg-gray-200 text-gray-900 rounded p-1' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-100 rounded p-1'}
          title="Search"
        >
          <SearchIcon className="w-4 h-4" />
        </button>
        <button
          onClick={() => onViewChange('git')}
          className={view === 'git' ? 'bg-gray-200 text-gray-900 rounded p-1' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-100 rounded p-1'}
          title="Git"
        >
          <GitIcon className="w-4 h-4" />
        </button>
      </div>

      <div className="flex-1 min-h-0 overflow-hidden">
        {view === 'files' && (
          <div className="h-full overflow-y-auto">
            <FileTree onFileSelect={onFileSelect} />
          </div>
        )}
        {view === 'git' && (
          <GitPanel onFileSelect={onDiffSelect} />
        )}
        {view === 'search' && (
          <SearchPanel onFileSelect={onFileSelect} />
        )}
      </div>
    </div>
  )
}

import { useState, useEffect } from 'react'

interface DiffViewerProps {
  filePath: string
}

export default function DiffViewer({ filePath }: DiffViewerProps) {
  const [diff, setDiff] = useState<string | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [loading, setLoading] = useState(true)
  const [isUntracked, setIsUntracked] = useState(false)

  useEffect(() => {
    setLoading(true)
    setError(null)
    window.api.gitDiff(filePath)
      .then(result => {
        if (result.ok && result.data) {
          setDiff(result.data)
          setIsUntracked(false)
        } else {
          window.api.readFile(filePath)
            .then(fileResult => {
              if (fileResult.ok && fileResult.data) {
                const content = fileResult.data.content
                setDiff(content.split('\n').map(l => `+${l}`).join('\n'))
                setIsUntracked(true)
              } else {
                setError(result.error ?? 'Failed to get diff')
              }
            })
            .catch(() => setError(result.error ?? 'Failed to get diff'))
        }
      })
      .catch(err => setError(err instanceof Error ? err.message : String(err)))
      .finally(() => setLoading(false))
  }, [filePath])

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full text-gray-400 text-sm">
        Loading diff...
      </div>
    )
  }

  if (error) {
    return (
      <div className="flex items-center justify-center h-full text-gray-400 text-sm">
        {error}
      </div>
    )
  }

  if (!diff) {
    return (
      <div className="flex items-center justify-center h-full text-gray-400 text-sm">
        No diff available
      </div>
    )
  }

  const lines = diff.split('\n')

  return (
    <div className="font-mono text-xs overflow-auto h-full">
      <table className="w-full border-collapse">
        <tbody>
          {isUntracked && (
            <tr>
              <td colSpan={2} className="px-3 py-1 text-yellow-700 bg-yellow-50 font-semibold">
                Untracked file — showing full content
              </td>
            </tr>
          )}
          {lines.map((line, i) => {
            let bg = ''
            let textColor = 'text-gray-800'
            if (line.startsWith('+++') || line.startsWith('---')) {
              bg = 'bg-blue-50'
              textColor = 'text-blue-700 font-semibold'
            } else if (line.startsWith('@@')) {
              bg = 'bg-blue-50/50'
              textColor = 'text-blue-600'
            } else if (line.startsWith('+')) {
              bg = 'bg-green-50'
              textColor = 'text-green-800'
            } else if (line.startsWith('-')) {
              bg = 'bg-red-50'
              textColor = 'text-red-800'
            }

            return (
              <tr key={i} className={bg}>
                <td className="px-2 py-0 text-right text-gray-300 select-none w-10 border-r border-gray-100">
                  {i + 1}
                </td>
                <td className={`px-3 py-0 whitespace-pre ${textColor}`}>
                  {line || ' '}
                </td>
              </tr>
            )
          })}
        </tbody>
      </table>
    </div>
  )
}

import { app, BrowserWindow, ipcMain, nativeTheme, dialog, shell } from 'electron'
import { join, basename, extname, dirname } from 'path'
import { existsSync, readdirSync, statSync, readFileSync, writeFileSync, mkdirSync } from 'fs'
import { execFile } from 'child_process'
import { simpleGit } from 'simple-git'
import { watch } from 'chokidar'
import { PiSDKBridge } from './pi-sdk-bridge'
import * as sessionService from './session-service'
import type { SessionInfo, ForkableMessage, ForkPoint } from '../renderer/src/types/session'

// Override app name & dock icon so macOS shows "Xi" instead of "Electron"
app.setName('Xi')
if (process.platform === 'darwin') {
  try {
    const dockIconPath = join(__dirname, 'icon.png')
    app.dock.setIcon(dockIconPath)
  } catch {}
}

let mainWindow: BrowserWindow | null = null
let piBridge: PiSDKBridge | null = null
let initialSessionPath: string | undefined

function createWindow(): void {
  const iconPath = join(__dirname, 'icon.png')
  mainWindow = new BrowserWindow({
    width: 1200,
    height: 800,
    backgroundColor: '#ffffff',
    titleBarStyle: 'hiddenInset',
    icon: iconPath,
    show: false,
    webPreferences: {
      preload: join(__dirname, '../preload/index.js'),
      sandbox: false
    }
  })

  mainWindow.on('ready-to-show', () => {
    mainWindow?.show()
  })

  mainWindow.on('closed', () => {
    mainWindow = null
  })

  mainWindow.webContents.on('context-menu', (event) => {
    event.preventDefault()
  })

  if (process.env.ELECTRON_RENDERER_URL) {
    mainWindow.loadURL(process.env.ELECTRON_RENDERER_URL)
  } else {
    mainWindow.loadFile(join(__dirname, '../renderer/index.html'))
  }
}

function broadcastToRenderers(channel: string, data: unknown): void {
  BrowserWindow.getAllWindows().forEach((win) => {
    if (!win.isDestroyed() && !win.webContents.isDestroyed()) {
      try {
        win.webContents.send(channel, data)
      } catch {}
    }
  })
}

function initPiBridge(sessionPath?: string): void {
  piBridge = new PiSDKBridge()
  initialSessionPath = sessionPath

  piBridge.on('event', (data: unknown) => {
    // In SDK mode, extension_ui_request arrives as a regular event
    if (typeof data === 'object' && data !== null) {
      const obj = data as Record<string, unknown>
      if (obj.type === 'extension_ui_request') {
        broadcastToRenderers('pi:extensionUiRequest', data)
        return
      }
    }
    broadcastToRenderers('pi:event', data)
  })

  piBridge.on('response', (data: unknown) => {
    broadcastToRenderers('pi:response', data)
  })

  piBridge.on('connected', () => {
    broadcastToRenderers('pi:stateChanged', { connected: true })
  })

  piBridge.on('disconnected', () => {
    broadcastToRenderers('pi:stateChanged', { connected: false })
  })

  piBridge.on('error', (err: Error) => {
    console.error('[PiSDKBridge]', err.message)
  })
}

function registerIpcHandlers(): void {
  ipcMain.handle('pi:sendCommand', (_event, command: Record<string, unknown>) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    piBridge.sendCommand(command)
    return { ok: true }
  })

  ipcMain.handle('pi:sendExtensionUIResponse', (_event, response: Record<string, unknown>) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    piBridge.sendExtensionUIResponse(response)
    return { ok: true }
  })

  ipcMain.handle('pi:getState', () => {
    return { connected: piBridge?.isConnected ?? false }
  })

  ipcMain.handle('pi:getAvailableModels', async () => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    try {
      const data = await piBridge.sendRpcCommand({ type: 'get_available_models' })
      return { ok: true, data }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('pi:setModel', async (_event, model: string, provider?: string) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    try {
      const command: Record<string, unknown> = { type: 'set_model', model }
      if (provider) command.provider = provider
      const data = await piBridge.sendRpcCommand(command)
      return { ok: true, data }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('pi:cycleModel', async (_event, direction?: 'forward' | 'backward') => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    try {
      const data = await piBridge.sendRpcCommand({ type: 'cycle_model', direction: direction ?? 'forward' })
      return { ok: true, data }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('pi:getModelInfo', async () => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    try {
      const data = await piBridge.sendRpcCommand({ type: 'get_state' })
      const state = data as Record<string, unknown>
      return { ok: true, data: { model: state.model ?? null, thinkingLevel: state.thinkingLevel ?? null } }
    } catch (err: unknown) {
