          style={{ left: LINE_LEFT, top: 0, bottom: 0, width: 1.5, backgroundColor: BLUE }}
        />
      )}
    </div>
  )
}

function GuideElbow({ active }: { active: boolean }) {
  const color = active ? BLUE : GRAY
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none overflow-visible"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      <div
        className="absolute"
        style={{ left: LINE_LEFT, top: 0, height: `calc(50% - ${R}px)`, width: 1.5, backgroundColor: color }}
      />
      <div
        className="absolute"
        style={{
          left: LINE_LEFT,
          top: `calc(50% - ${R}px)`,
          width: R,
          height: R,
          borderLeft: `1.5px solid ${color}`,
          borderBottom: `1.5px solid ${color}`,
          borderBottomLeftRadius: R,
        }}
      />
      <div
        className="absolute"
        style={{
          left: LINE_LEFT + R,
          top: `calc(50% - 1.5px)`,
          width: SLOT_W - LINE_LEFT - R + 3,
          height: 1.5,
          backgroundColor: color,
        }}
      />
    </div>
  )
}

function GuideSlot() {
  return (
    <div
      className="flex-shrink-0"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    />
  )
}

function DotSlot({
  active,
  hasChildren,
  isExpanded,
  highlight,
  completed,
}: {
  active: boolean
  hasChildren: boolean
  isExpanded: boolean
  highlight: boolean
  completed: boolean
}) {
  return (
    <div
      className="flex-shrink-0 flex items-center justify-center relative"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      <div
        className={
          active
            ? 'w-2.5 h-2.5 rounded-full bg-blue-500 border-2 border-blue-500 flex-shrink-0'
            : completed
              ? 'w-2.5 h-2.5 rounded-full bg-gray-300 border-2 border-gray-300 flex-shrink-0'
              : 'w-2.5 h-2.5 rounded-full bg-white border-2 border-gray-300 group-hover:border-blue-500 flex-shrink-0'
        }
      />
      {hasChildren && isExpanded && (
        <div
          className="absolute"
          style={{
            left: LINE_LEFT,
            top: 'calc(50% + 5px)',
            bottom: 0,
            width: 1.5,
            backgroundColor: highlight ? BLUE : GRAY,
          }}
        />
      )}
    </div>
  )
}

function SessionNode({
  node,
  ancestorLines,
  currentSessionPath,
  isOnActivePath,
  onSwitch,
  onRename,
  onDelete,
  onSetSessionStatus,
  onForkFromEnd,
  onNewSession,
  onContextMenu,
  triggerRenamePath,
  onRenameTriggered,
  triggerForkPath,
  onForkTriggered,
}: {
  node: SessionTreeNode
  ancestorLines: { hasLine: boolean; highlight: boolean; branchActive: boolean }[]
  currentSessionPath: string | null
  isOnActivePath: boolean
  onSwitch: (path: string) => void
  onRename: (name: string) => void
  onDelete: (path: string) => Promise<boolean>
  onSetSessionStatus: (sessionPath: string, status: 'active' | 'completed') => Promise<boolean>
  onForkFromEnd: (sessionPath: string, name: string) => void
  onNewSession: (name: string, parentSessionPath: string) => void
  onContextMenu: (e: React.MouseEvent, session: SessionInfo) => void
  triggerRenamePath: string | null
  onRenameTriggered: () => void
  triggerForkPath: string | null
  onForkTriggered: () => void
}): React.ReactElement {
  const [isExpanded, setIsExpanded] = useState(true)
  const [isRenaming, setIsRenaming] = useState(false)
  const [renameValue, setRenameValue] = useState(getDisplayName(node.session))
  const [confirmDelete, setConfirmDelete] = useState(false)
  const [isForking, setIsForking] = useState(false)
  const [forkName, setForkName] = useState('')
  const [isCreatingChild, setIsCreatingChild] = useState(false)
  const [childName, setChildName] = useState('')
  const isCompleted = node.session.status === 'completed'
  const isActive = currentSessionPath === node.session.filePath
  const hasChildren = node.children.length > 0

  useEffect(() => {
    if (triggerRenamePath === node.session.filePath) {
      setIsRenaming(true)
      setRenameValue(getDisplayName(node.session))
      onRenameTriggered()
    }
  }, [triggerRenamePath, node.session.filePath, onRenameTriggered])

  useEffect(() => {
    if (triggerForkPath === node.session.filePath) {
      setIsForking(true)
      setForkName('')
      onForkTriggered()
    }
  }, [triggerForkPath, node.session.filePath, onForkTriggered])

  const handleDoubleClick = useCallback(() => {
    setIsRenaming(true)
    setRenameValue(getDisplayName(node.session))
  }, [node.session])

  const handleRenameSubmit = useCallback(() => {
    const trimmed = renameValue.trim()
    if (trimmed && trimmed !== getDisplayName(node.session)) {
      onRename(trimmed)
    }
    setIsRenaming(false)
  }, [renameValue, node.session, onRename])

  const hasChildOnActivePath = node.children.some(
    (child) =>
      currentSessionPath === child.session.filePath ||
      isDescendantOf(child, currentSessionPath)
  )

  const renderGuides = () => {
    if (ancestorLines.length === 0) return null
    return ancestorLines.map((entry, i) => {
      const isConnector = i === ancestorLines.length - 1
      if (isConnector) {
        if (entry.hasLine) {
          return <GuideBranch key={i} active={entry.branchActive} highlight={entry.highlight && !entry.branchActive} />
        }
        return <GuideElbow key={i} active={entry.branchActive} />
      }
      if (entry.hasLine) {
        return <GuideLine key={i} highlight={entry.highlight && !entry.branchActive} />
      }
      return <GuideSlot key={i} />
    })
  }

  return (
    <div>
      <div
        className={`group flex items-center rounded cursor-pointer transition-colors ${
          isActive
            ? isCompleted
              ? 'bg-gray-100 text-gray-400'
              : 'bg-gray-100 text-gray-900'
            : isCompleted
              ? 'text-gray-400 hover:bg-gray-100/60 hover:text-gray-500'
              : 'text-gray-600 hover:bg-gray-100/60 hover:text-gray-800'
        }`}
        onClick={() => onSwitch(node.session.filePath)}
        onDoubleClick={handleDoubleClick}
        onContextMenu={(e) => onContextMenu(e, node.session)}
      >
        {renderGuides()}
        <DotSlot
          active={isOnActivePath || isActive || node.session.isMain}
          hasChildren={hasChildren}
          isExpanded={isExpanded}
          highlight={hasChildOnActivePath}
          completed={isCompleted}
        />
        <div className="flex-1 flex items-center gap-1 py-1.5 pr-2 min-w-0">
          {isRenaming ? (
            <input
              autoFocus
              value={renameValue}
              onChange={(e) => setRenameValue(e.target.value)}
              onBlur={handleRenameSubmit}
              onKeyDown={(e) => {
                if (e.key === 'Enter') handleRenameSubmit()
                if (e.key === 'Escape') setIsRenaming(false)
              }}
              onClick={(e) => e.stopPropagation()}
              className="flex-1 min-w-0 bg-gray-100 rounded px-1 py-0.5 text-xs text-gray-900 outline-none border border-gray-300 focus:border-blue-500"
            />
          ) : (
            <span className={`flex-1 truncate text-xs ${isCompleted ? 'line-through' : ''}`}>
              {getDisplayName(node.session)}
            </span>
          )}

          <span className="flex-shrink-0 text-[10px] text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity">
            {formatRelativeTime(node.session.createdAt)}
          </span>

          {hasChildren && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsExpanded(!isExpanded)
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title={isExpanded ? 'Collapse' : 'Expand'}
            >
              <svg
                className={`w-3 h-3 transition-transform ${isExpanded ? 'rotate-90' : ''}`}
                fill="currentColor"
                viewBox="0 0 20 20"
              >
                <path
                  fillRule="evenodd"
                  d="M7.21 14.77a.75.75 0 01.02-1.06L11.168 10 7.23 6.29a.75.75 0 111.04-1.08l4.5 4.25a.75.75 0 010 1.08l-4.5 4.25a.75.75 0 01-1.06-.02z"
                  clipRule="evenodd"
                />
              </svg>
            </button>
          )}

          {node.session.parentSessionPath && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                onSwitch(node.session.parentSessionPath!)
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-blue-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title="Go to parent session"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" />
              </svg>
            </button>
          )}

          {isActive && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsForking(true)
                setForkName('')
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-purple-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title="Fork"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M5 12h4m6 0h4M12 5v4m0 6v4" />
                <circle cx="5" cy="12" r="2" />
                <circle cx="19" cy="12" r="2" />
                <circle cx="12" cy="5" r="2" />
                <circle cx="12" cy="19" r="2" />
              </svg>
            </button>
          )}

          <button
            onClick={(e) => {
              e.stopPropagation()
              setIsCreatingChild(true)
              setChildName('')
            }}
            className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-blue-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
            title="New child session"
          >
            <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
            </svg>
          </button>

          {!node.session.isMain && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                if (confirmDelete) {
                  onDelete(node.session.filePath)
                  setConfirmDelete(false)
                } else {
                  setConfirmDelete(true)
                }
              }}
              onBlur={() => setConfirmDelete(false)}
              className={`flex-shrink-0 rounded p-0.5 opacity-0 group-hover:opacity-100 transition-colors ${
                confirmDelete
                  ? 'bg-red-600 text-white opacity-100'
                  : 'text-gray-400 hover:text-red-500 hover:bg-gray-100'
              }`}
            >
              {confirmDelete ? (
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              ) : (
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                </svg>
              )}
            </button>
          )}
        </div>
      </div>

      {isForking && (
        <div
          className="flex items-center gap-1 pl-8 pr-2 py-1"
          onClick={(e) => e.stopPropagation()}
        >
          <input
            autoFocus
            value={forkName}
            onChange={(e) => setForkName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                const trimmed = forkName.trim()
                if (trimmed) {
                  onForkFromEnd(node.session.filePath, trimmed)
                  setIsForking(false)
                  setForkName('')
                }
              }
              if (e.key === 'Escape') {
                setIsForking(false)
                setForkName('')
              }
            }}
            placeholder="Fork name"
            className="flex-1 min-w-0 rounded border border-purple-300 bg-white px-2 py-0.5 text-xs text-gray-900 outline-none focus:border-purple-500"
          />
          <button
            onClick={() => {
              const trimmed = forkName.trim()
              if (trimmed) {
                onForkFromEnd(node.session.filePath, trimmed)
                setIsForking(false)
                setForkName('')
              }
            }}
            disabled={!forkName.trim()}
            className="rounded bg-purple-600 px-2 py-0.5 text-xs font-medium text-white hover:bg-purple-500 disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Fork
          </button>
          <button
            onClick={() => {
              setIsForking(false)
              setForkName('')
            }}
            className="rounded px-1 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 text-xs transition-colors"
            title="Cancel"
          >
            ✕
          </button>
        </div>
      )}

      {isCreatingChild && (
        <div
          className="flex items-center gap-1 pl-8 pr-2 py-1"
          onClick={(e) => e.stopPropagation()}
        >
          <input
            autoFocus
            value={childName}
            onChange={(e) => setChildName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                const trimmed = childName.trim()
                if (trimmed) {
                  onNewSession(trimmed, node.session.filePath)
                  setIsCreatingChild(false)
                  setChildName('')
                }
              }
              if (e.key === 'Escape') {
                setIsCreatingChild(false)
                setChildName('')
              }
            }}
            placeholder="Child session name"
            className="flex-1 min-w-0 rounded border border-blue-300 bg-white px-2 py-0.5 text-xs text-gray-900 outline-none focus:border-blue-500"
          />
          <button
            onClick={() => {
              const trimmed = childName.trim()
              if (trimmed) {
                onNewSession(trimmed, node.session.filePath)
                setIsCreatingChild(false)
                setChildName('')
              }
            }}
            disabled={!childName.trim()}
            className="rounded bg-blue-600 px-2 py-0.5 text-xs font-medium text-white hover:bg-blue-500 disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Create
          </button>
          <button
            onClick={() => {
              setIsCreatingChild(false)
              setChildName('')
            }}
            className="rounded px-1 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 text-xs transition-colors"
            title="Cancel"
          >
            ✕
          </button>
        </div>
      )}

      {hasChildren && isExpanded && (
        <div>
          {node.children.map((child, i) => {
            const childIsActivePath =
              currentSessionPath === child.session.filePath ||
              isDescendantOf(child, currentSessionPath)
            const laterSiblingOnActivePath = node.children
              .slice(i + 1)
              .some(
                (sibling) =>
                  currentSessionPath === sibling.session.filePath ||
                  isDescendantOf(sibling, currentSessionPath)
              )
            const onPath = childIsActivePath || laterSiblingOnActivePath
            const newAncestorLines = [
              ...ancestorLines.map((entry) => ({
                hasLine: entry.hasLine,
                highlight: entry.branchActive
                  ? (entry.highlight && childIsActivePath)
                  : entry.highlight,
                branchActive: entry.branchActive && childIsActivePath,
              })),
              {
                hasLine: i < node.children.length - 1,
                highlight: onPath,
                branchActive: childIsActivePath,
              },
            ]
            return (
              <SessionNode
                key={child.session.filePath}
                node={child}
                ancestorLines={newAncestorLines}
                currentSessionPath={currentSessionPath}
                isOnActivePath={childIsActivePath}
                onSwitch={onSwitch}
                onRename={onRename}
                onDelete={onDelete}
                onSetSessionStatus={onSetSessionStatus}
                onForkFromEnd={onForkFromEnd}
                onNewSession={onNewSession}
                onContextMenu={onContextMenu}
                triggerRenamePath={triggerRenamePath}
                onRenameTriggered={onRenameTriggered}
                triggerForkPath={triggerForkPath}
                onForkTriggered={onForkTriggered}
              />
            )
          })}
        </div>
      )}
    </div>
  )
}

function SessionSidebar({
  sessions,
  currentSession,
  onSwitchSession,
  onNewSession,
  onRenameSession,
  onDeleteSession,
  onSetSessionStatus,
  onForkFromEnd,
  isCollapsed,
  onToggleCollapse,
  width,
  onResizeStart,
}: SessionSidebarProps): React.ReactElement {
  const [contextMenu, setContextMenu] = useState<{
    x: number
    y: number
    session: SessionInfo
  } | null>(null)
  const [contextMenuPos, setContextMenuPos] = useState<{ x: number; y: number } | null>(null)
  const [triggerRenamePath, setTriggerRenamePath] = useState<string | null>(null)
  const [triggerForkPath, setTriggerForkPath] = useState<string | null>(null)

  const projects = sessions?.projects ?? []
  const root = projects[0]?.root ?? null

  const handleContextMenu = useCallback((e: React.MouseEvent, session: SessionInfo) => {
    e.preventDefault()
    e.stopPropagation()
    setContextMenu({ x: e.clientX, y: e.clientY, session })
    setContextMenuPos(null) // will be adjusted in useEffect
  }, [])

  const handleRenameTriggered = useCallback(() => {
    setTriggerRenamePath(null)
  }, [])

  const handleForkTriggered = useCallback(() => {
    setTriggerForkPath(null)
  }, [])

  useEffect(() => {
    if (!contextMenu) return

    const handleClick = () => setContextMenu(null)
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setContextMenu(null)
    }

    document.addEventListener('click', handleClick)
    document.addEventListener('keydown', handleKeyDown)

    return () => {
      document.removeEventListener('click', handleClick)
      document.removeEventListener('keydown', handleKeyDown)
    }
  }, [contextMenu])

  // Adjust context menu position to keep it within viewport
  useEffect(() => {
    if (!contextMenu) return
    const el = document.querySelector('[data-context-menu]') as HTMLDivElement | null
    if (!el) return
    const rect = el.getBoundingClientRect()
    const vw = window.innerWidth
    const vh = window.innerHeight
    let x = contextMenu.x
    let y = contextMenu.y
    if (x + rect.width > vw) x = vw - rect.width - 4
    if (y + rect.height > vh) y = vh - rect.height - 4
    if (x < 0) x = 4
    if (y < 0) y = 4
    setContextMenuPos({ x, y })
  }, [contextMenu])

  if (isCollapsed) {
    return (
      <div className="flex flex-col items-center w-12 bg-gray-50 border-r border-gray-200 pb-3" />
    )
  }

  return (
    <div
      className="relative flex flex-col bg-gray-50 overflow-hidden"
      style={{ width: `${width}px` }}
    >
      <div className="flex-1 overflow-y-auto py-2">
        {projects.length === 0 || !root ? (
          <div className="px-3 py-6 text-center text-xs text-gray-600">
            No sessions found
          </div>
        ) : (
          <SessionNode
            node={root}
            ancestorLines={[]}
            currentSessionPath={currentSession?.filePath ?? null}
            isOnActivePath={true}
            onSwitch={onSwitchSession}
            onRename={onRenameSession}
            onDelete={onDeleteSession}
            onSetSessionStatus={onSetSessionStatus}
            onForkFromEnd={onForkFromEnd}
            onNewSession={onNewSession}
            onContextMenu={handleContextMenu}
            triggerRenamePath={triggerRenamePath}
            onRenameTriggered={handleRenameTriggered}
            triggerForkPath={triggerForkPath}
            onForkTriggered={handleForkTriggered}
          />
        )}
      </div>

      <div
        className="absolute top-0 right-0 w-1 h-full cursor-col-resize hover:w-1.5 hover:bg-blue-500/30 transition-all z-10"
        onMouseDown={onResizeStart}
      />

      {contextMenu && (
        <div
          data-context-menu
          className="fixed z-50 bg-white border border-gray-200 rounded-lg shadow-lg py-1 text-xs min-w-[140px]"
          style={{ left: contextMenuPos?.x ?? contextMenu.x, top: contextMenuPos?.y ?? contextMenu.y }}
          onClick={(e) => e.stopPropagation()}
        >
          <div
            className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
            onClick={() => {
              setTriggerRenamePath(contextMenu.session.filePath)
              setContextMenu(null)
            }}
          >
            Rename
          </div>
          <div
            className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
            onClick={() => {
              const newStatus = contextMenu.session.status === 'completed' ? 'active' : 'completed'
              onSetSessionStatus(contextMenu.session.filePath, newStatus)
              setContextMenu(null)
            }}
          >
            {contextMenu.session.status === 'completed' ? 'Mark as active' : 'Mark as completed'}
          </div>
          {contextMenu.session.parentSessionPath && (
            <div
              className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
              onClick={() => {
                onSwitchSession(contextMenu.session.parentSessionPath!)
                setContextMenu(null)
              }}
            >
              Go to parent
            </div>
          )}
          {contextMenu.session.filePath === currentSession?.filePath && (
            <div
              className="px-3 py-1.5 hover:bg-purple-50 cursor-pointer text-purple-600"
              onClick={() => {
                setTriggerForkPath(contextMenu.session.filePath)
                setContextMenu(null)
              }}
            >
              Fork
            </div>
          )}
          {!contextMenu.session.isMain && (
            <div
              className="px-3 py-1.5 hover:bg-red-50 cursor-pointer text-red-600"
              onClick={() => {
                onDeleteSession(contextMenu.session.filePath)
                setContextMenu(null)
              }}
            >
              Delete
            </div>
          )}
        </div>
      )}
    </div>
  )
}

export default SessionSidebar

/**
 * Session management types for Pi session sidebar.
 *
 * Pi sessions are stored as JSONL files at:
 *   ~/.pi/agent/sessions/--<encoded-cwd>--/<timestamp>_<uuid>.jsonl
 *
 * Each file has a tree structure (id/parentId) and a header with metadata.
 * Inter-session relationships are tracked via `parentSession` in the header.
 */

/** Parsed header from a Pi session JSONL file (first line). */
export interface SessionFileHeader {
  type: 'session'
  version: number
  id: string
  timestamp: string
  cwd: string
  parentSession?: string
}

/** Lightweight metadata for a session file, used in the sidebar list. */
export interface SessionInfo {
  /** Absolute path to the .jsonl file on disk. */
  filePath: string
  /** UUID from the session header. */
  sessionId: string
  /** User-defined display name (from session_info entries), or null. */
  name: string | null
  /** ISO timestamp of session creation. */
  createdAt: string
  /** Working directory the session was started in. */
  cwd: string
  /** Absolute path to the parent session file, or null. */
  parentSessionPath: string | null
  /** Number of user messages in the session. */
  messageCount: number
  /** Whether this is the "main" session for its project. */
  isMain: boolean
  /** Session status: 'active' or 'completed'. null means active (default). */
  status: 'active' | 'completed' | null
}

/**
 * A node in the inter-session tree.
 * Each project has a tree of sessions linked by parentSession.
 */
export interface SessionTreeNode {
  session: SessionInfo
  children: SessionTreeNode[]
}

/**
 * A project's session tree.
 * Each project (working directory) has one tree rooted at the "main" session.
 */
export interface ProjectSessionTree {
  /** The decoded working directory path. */
  projectPath: string
  /** The encoded directory name (e.g., "--Users-foo-bar--"). */
  encodedDir: string
  /** Root of the session tree (the "main" session). */
  root: SessionTreeNode | null
  /** All sessions in this project (flat list for lookup). */
  allSessions: SessionInfo[]
}

/** Result of listing all sessions across all projects. */
export interface SessionListResult {
  projects: ProjectSessionTree[]
}

/** A forkable user message entry (from get_fork_messages RPC). */
export interface ForkableMessage {
  entryId: string
  text: string
}

/** A recorded fork point in a parent session's JSONL file. */
export interface ForkPoint {
  entryId: string
  childName: string
}

/** IPC channels for session management between renderer and main process. */
export interface SessionIpcApi {
  /** List all sessions grouped by project. */
  listSessions: () => Promise<SessionListResult>
  /** Get forkable user messages for the current session. */
  getForkMessages: () => Promise<ForkableMessage[]>
  /** Fork at a specific entry, creating a new session. */
  forkAtEntry: (entryId: string, name?: string) => Promise<{ success: boolean; text?: string; error?: string }>
  /** Switch to a different session. */
  switchSession: (sessionPath: string) => Promise<{ success: boolean; error?: string }>
  /** Create a new session with a name and optional parent. */
  newSession: (name: string, parentSessionPath?: string) => Promise<{ success: boolean; error?: string }>
  /** Rename a session. */
  renameSession: (name: string) => Promise<{ success: boolean; error?: string }>
  /** Get current session state. */
  getCurrentSession: () => Promise<SessionInfo | null>
  /** Refresh session list (after fork/switch/new operations). */
  refreshSessions: () => Promise<SessionListResult>
  /** Get all messages in the current Pi session (raw Pi message format). */
  getMessages: () => Promise<unknown[]>
  /** Delete a session by file path. Cannot delete the active session. */
  deleteSession: (sessionPath: string) => Promise<{ success: boolean; error?: string }>
  /** Get fork points recorded in a session file. */
  getForkPoints: (sessionPath: string) => Promise<ForkPoint[]>
  /** Clear the current session's conversation (delete JSONL, restart Pi, rename). */
  clearSession: () => Promise<{ success: boolean; error?: string }>
  /** Set session status (active/completed). Pure file operation, no Pi RPC. */
  setSessionStatus: (sessionPath: string, status: 'active' | 'completed') => Promise<{ success: boolean; error?: string }>
}

/** Model info returned by Pi SDK. */
export interface PiModelInfo {
  provider: string
  id: string
  name: string
  hasAuth: boolean
  reasoning: boolean
  contextWindow: number
}

/** Result from getAvailableModels IPC call. */
export interface GetAvailableModelsResult {
  ok: boolean
  data?: { models: PiModelInfo[] }
  error?: string
}

/** Result from setModel IPC call. */
export interface SetModelResult {
  ok: boolean
  data?: PiModelInfo | null
  error?: string
}

/** Result from cycleModel IPC call. */
export interface CycleModelResult {
  ok: boolean
  data?: {
    model: PiModelInfo | null
    thinkingLevel: string
    isScoped: boolean
  }
  error?: string
}

/** Result from getModelInfo IPC call. */
export interface GetModelInfoResult {
  ok: boolean
  data?: { model: PiModelInfo | null; thinkingLevel: string | null }
  error?: string
}

/** IPC channels for file system operations between renderer and main process. */
export interface FileSystemIpcApi {
  readDirectory: (dirPath: string) => Promise<{
    ok: boolean
    entries?: Array<{ name: string; path: string; isDirectory: boolean }>
    error?: string
  }>
}

