    }
  }, [refresh])

  const handleStage = useCallback(async (filePath: string) => {
    setStaging(filePath)
    try {
      const result = await window.api.gitStage([filePath])
      if (result.ok) await refresh()
    } finally {
      setStaging(null)
    }
  }, [refresh])

  const handleUnstage = useCallback(async (filePath: string) => {
    setStaging(filePath)
    try {
      const result = await window.api.gitUnstage([filePath])
      if (result.ok) await refresh()
    } finally {
      setStaging(null)
    }
  }, [refresh])

  const handleStageAll = useCallback(async () => {
    if (!status) return
    const paths = status.files.filter(f => !f.staged).map(f => f.path)
    if (paths.length === 0) return
    setStaging('__all__')
    try {
      await window.api.gitStage(paths)
      await refresh()
    } finally {
      setStaging(null)
    }
  }, [status, refresh])

  const handleDiscardAll = useCallback(async () => {
    if (!status) return
    const paths = status.files.filter(f => !f.staged && f.status !== '?').map(f => f.path)
    if (paths.length === 0) return
    setStaging('__discard__')
    try {
      await window.api.gitDiscard(paths)
      await refresh()
    } finally {
      setStaging(null)
    }
  }, [status, refresh])

  const handleCommit = useCallback(async () => {
    if (!commitMsg.trim()) return
    setCommitting(true)
    try {
      const result = await window.api.gitCommit(commitMsg.trim())
      if (result.ok) {
        setCommitMsg('')
        await refresh()
      }
    } finally {
      setCommitting(false)
    }
  }, [commitMsg, refresh])

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full text-gray-400 text-xs">
        Loading...
      </div>
    )
  }

  if (error) {
    return (
      <div className="p-3 text-xs text-gray-400">
        {error}
      </div>
    )
  }

  if (!status) return null

  const staged = status.files.filter(f => f.staged)
  const unstaged = status.files.filter(f => !f.staged && f.status !== '?')
  const untracked = status.files.filter(f => f.status === '?')

  const hasUnstagedOrUntracked = unstaged.length > 0 || untracked.length > 0
  const hasUnstagedChanges = unstaged.length > 0

  return (
    <div className="text-xs flex flex-col h-full">
      {/* Branch header */}
      <div className="px-3 py-2 border-b border-gray-200 flex items-center gap-2 flex-shrink-0">
        <span className="font-medium text-gray-700">{status.branch}</span>
        {status.ahead > 0 && <span className="text-green-600">↑{status.ahead}</span>}
        {status.behind > 0 && <span className="text-amber-600">↓{status.behind}</span>}
        {hasUnstagedOrUntracked && (
          <div className="ml-auto flex items-center gap-1">
            <button
              onClick={handleStageAll}
              className="rounded p-1 text-gray-400 hover:text-green-600 hover:bg-gray-100 transition-colors"
              disabled={staging !== null}
              title="Stage All"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
              </svg>
            </button>
            {hasUnstagedChanges && (
              <button
                onClick={handleDiscardAll}
                className="rounded p-1 text-gray-400 hover:text-red-500 hover:bg-gray-100 transition-colors"
                disabled={staging !== null}
                title="Discard All Changes"
              >
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M20 12H4" />
                </svg>
              </button>
            )}
          </div>
        )}
        {!hasUnstagedOrUntracked && (
          <button
            onClick={refresh}
            className="ml-auto rounded p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
            title="Refresh"
          >
            <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </button>
        )}
      </div>

      {/* Sub-tab: Changes / Log */}
      <div className="flex border-b border-gray-200 flex-shrink-0">
        <button
          onClick={() => setSubTab('changes')}
          className={`flex-1 py-1.5 text-xs font-medium transition-colors ${
            subTab === 'changes'
              ? 'text-blue-600 border-b-2 border-blue-600'
              : 'text-gray-500 hover:text-gray-700'
          }`}
        >
          Changes
          {status.files.length > 0 && (
            <span className="ml-1 text-[10px] text-gray-400">({status.files.length})</span>
          )}
        </button>
        <button
          onClick={() => setSubTab('log')}
          className={`flex-1 py-1.5 text-xs font-medium transition-colors ${
            subTab === 'log'
              ? 'text-blue-600 border-b-2 border-blue-600'
              : 'text-gray-500 hover:text-gray-700'
          }`}
        >
          Log
        </button>
      </div>

      {/* Content area */}
      <div className="flex-1 overflow-y-auto min-h-0">
        {subTab === 'changes' && (
          <>
            {staged.length > 0 && (
              <div className="border-b border-gray-200">
                <div className="px-3 py-1.5 text-gray-500 font-medium">Staged Changes ({staged.length})</div>
                {staged.map(f => (
                  <div key={f.path} className="px-3 py-1 flex items-center gap-1 hover:bg-gray-100 group" title={f.path}>
                    <span className={`w-4 text-center font-mono font-semibold ${statusColor(f.status)}`}>{statusLabel(f.status)}</span>
                    <span className="text-gray-700 truncate flex-1 cursor-pointer" onClick={() => onFileSelect?.(f.path)}>{f.path}</span>
                    <button
                      onClick={() => handleUnstage(f.path)}
                      disabled={staging !== null}
                      className="rounded p-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-200 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0"
                      title="Unstage"
                    >
                      <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M20 12H4" />
                      </svg>
                    </button>
                  </div>
                ))}
              </div>
            )}

            {unstaged.length > 0 && (
              <div className="border-b border-gray-200">
                <div className="px-3 py-1.5 text-gray-500 font-medium">Changes ({unstaged.length})</div>
                {unstaged.map(f => (
                  <div key={f.path} className="px-3 py-1 flex items-center gap-1 hover:bg-gray-100 group" title={f.path}>
                    <span className={`w-4 text-center font-mono font-semibold ${statusColor(f.status)}`}>{statusLabel(f.status)}</span>
                    <span className="text-gray-700 truncate flex-1 cursor-pointer" onClick={() => onFileSelect?.(f.path)}>{f.path}</span>
                    <button
                      onClick={() => handleStage(f.path)}
                      disabled={staging !== null}
                      className="rounded p-0.5 text-gray-400 hover:text-green-600 hover:bg-gray-200 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0"
                      title="Stage"
                    >
                      <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
                      </svg>
                    </button>
                  </div>
                ))}
              </div>
            )}

            {untracked.length > 0 && (
              <div className="border-b border-gray-200">
                <div className="px-3 py-1.5 text-gray-500 font-medium">Untracked ({untracked.length})</div>
                {untracked.map(f => (
                  <div key={f.path} className="px-3 py-1 flex items-center gap-1 hover:bg-gray-100 group" title={f.path}>
                    <span className={`w-4 text-center font-mono font-semibold ${statusColor(f.status)}`}>U</span>
                    <span className="text-gray-700 truncate flex-1 cursor-pointer" onClick={() => onFileSelect?.(f.path)}>{f.path}</span>
                    <button
                      onClick={() => handleStage(f.path)}
                      disabled={staging !== null}
                      className="rounded p-0.5 text-gray-400 hover:text-green-600 hover:bg-gray-200 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0"
                      title="Stage"
                    >
                      <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
                      </svg>
                    </button>
                  </div>
                ))}
              </div>
            )}

            {status.files.length === 0 && (
              <div className="px-3 py-4 text-gray-400 text-center">
                No changes
                <div className="mt-1 text-[10px]">
                  Switch to <button onClick={() => setSubTab('log')} className="text-blue-500 hover:underline">Log</button> to see commit history
                </div>
              </div>
            )}
          </>
        )}

        {subTab === 'log' && (
          <GitLogList onCommitFileSelect={onCommitFileSelect} />
        )}
      </div>

      {/* Commit input (only in Changes tab with staged files) */}
      {subTab === 'changes' && staged.length > 0 && (
        <div className="border-t border-gray-200 p-2 flex-shrink-0">
          <textarea
            value={commitMsg}
            onChange={e => setCommitMsg(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter' && (e.metaKey || e.ctrlKey) && commitMsg.trim()) {
                e.preventDefault()
                handleCommit()
              }
            }}
            placeholder="Commit message (⌘+Enter)"
            className="w-full resize-none border border-gray-200 rounded px-2 py-1.5 text-xs focus:outline-none focus:border-blue-400"
            rows={2}
            disabled={committing}
          />
          <button
            onClick={handleCommit}
            disabled={!commitMsg.trim() || committing}
            className="w-full mt-1 rounded bg-blue-600 px-3 py-1.5 text-xs font-medium text-white hover:bg-blue-500 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors"
          >
            {committing ? 'Committing...' : 'Commit'}
          </button>
        </div>
      )}
    </div>
  )
}

import { useState, useEffect, useCallback, useRef } from 'react'
import TreeGraphRow, { type GuideEntry, TREE_DEFAULTS } from './TreeGraph'
import CommitDetailInline from './CommitDetailInline'
import type { CommitEntry, CommitDetail } from '../types/git'

const BRANCH_COLORS = [
  '#3b82f6', // blue-500
  '#10b981', // emerald-500
  '#8b5cf6', // violet-500
  '#f59e0b', // amber-500
  '#ef4444', // red-500
  '#06b6d4', // cyan-500
  '#ec4899', // pink-500
  '#84cc16', // lime-500
]

function getBranchColor(branchName: string): string {
  // Simple hash to assign a stable color per branch name
  let hash = 0
  for (let i = 0; i < branchName.length; i++) {
    hash = ((hash << 5) - hash + branchName.charCodeAt(i)) | 0
  }
  return BRANCH_COLORS[Math.abs(hash) % BRANCH_COLORS.length]
}

function formatRelativeTime(dateStr: string): string {
  try {
    const now = Date.now()
    const then = new Date(dateStr).getTime()
    if (isNaN(then)) return dateStr
    const diffMs = now - then
    const diffMin = Math.floor(diffMs / 60000)
    const diffHr = Math.floor(diffMs / 3600000)
    const diffDay = Math.floor(diffMs / 86400000)

    if (diffMin < 1) return 'just now'
    if (diffMin < 60) return `${diffMin}m ago`
    if (diffHr < 24) return `${diffHr}h ago`
    if (diffDay < 30) return `${diffDay}d ago`
    return new Date(dateStr).toLocaleDateString()
  } catch {
    return dateStr
  }
}

/** Parse refs string to extract branch names and tags */
function parseRefs(refsStr: string): { branches: string[]; tags: string[]; isHead: boolean } {
  const branches: string[] = []
  const tags: string[] = []
  let isHead = false

  if (!refsStr) return { branches, tags, isHead }

  // refs format: "HEAD -> main, origin/main, tag: v1.0"
  const parts = refsStr.split(',').map(s => s.trim()).filter(Boolean)
  for (const part of parts) {
    if (part.startsWith('HEAD -> ')) {
      isHead = true
      const branch = part.replace('HEAD -> ', '').trim()
      branches.push(branch)
    } else if (part.startsWith('tag: ')) {
      tags.push(part.replace('tag: ', '').trim())
    } else {
      branches.push(part)
    }
  }

  return { branches, tags, isHead }
}

/** Determine the primary branch name for a commit (for coloring) */
function getCommitBranch(refsStr: string): string | null {
  const { branches } = parseRefs(refsStr)
  // Return the first local branch (not origin/) or null
  for (const b of branches) {
    if (!b.startsWith('origin/') && !b.startsWith('upstream/')) return b
  }
  return branches[0] ?? null
}

export default function GitLogList({
  onCommitFileSelect,
}: {
  onCommitFileSelect?: (hash: string, filePath: string) => void
}) {
  const [commits, setCommits] = useState<CommitEntry[]>([])
  const [loading, setLoading] = useState(true)
  const [loadingMore, setLoadingMore] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [expandedHash, setExpandedHash] = useState<string | null>(null)
  const [expandedDetail, setExpandedDetail] = useState<CommitDetail | null>(null)
  const [detailLoading, setDetailLoading] = useState(false)
  const [hasMore, setHasMore] = useState(true)
  const skipRef = useRef(0)

  const loadCommits = useCallback(async (skip: number, append: boolean) => {
    if (skip === 0) setLoading(true)
    else setLoadingMore(true)
    setError(null)
    try {
      const result = await window.api.gitLog({ maxCount: 50, skip })
      if (result.ok && result.data) {
        const newCommits = result.data
        if (append) {
          setCommits(prev => [...prev, ...newCommits])
        } else {
          setCommits(newCommits)
        }
        setHasMore(newCommits.length >= 50)
        skipRef.current = skip + newCommits.length
      } else {
        setError(result.error ?? 'Failed to load git log')
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err))
    } finally {
      setLoading(false)
      setLoadingMore(false)
    }
  }, [])

  useEffect(() => {
    loadCommits(0, false)
  }, [loadCommits])

  const handleLoadMore = useCallback(() => {
    loadCommits(skipRef.current, true)
  }, [loadCommits])

  const handleToggleCommit = useCallback(async (hash: string) => {
    if (expandedHash === hash) {
      setExpandedHash(null)
      setExpandedDetail(null)
      return
    }

    setExpandedHash(hash)
    setDetailLoading(true)
    setExpandedDetail(null)
    try {
      const result = await window.api.gitCommitDetail(hash)
      if (result.ok && result.data) {
        setExpandedDetail(result.data)
      }
    } catch {
      // Silently fail — detail will just be empty
    } finally {
      setDetailLoading(false)
    }
  }, [])

  if (loading) {
    return (
      <div className="flex items-center justify-center py-8 text-gray-400 text-xs">
        Loading log...
      </div>
    )
  }

  if (error) {
    return (
      <div className="px-3 py-4 text-gray-400 text-center">
        {error}
      </div>
    )
  }

  if (commits.length === 0) {
    return (
      <div className="px-3 py-4 text-gray-400 text-center">
        No commits found
      </div>
    )
  }

  // Track which branches have been seen to assign colors
  const branchColorMap = new Map<string, string>()
  let colorIdx = 0
  const getOrAssignColor = (branch: string): string => {
    let color = branchColorMap.get(branch)
    if (!color) {
      color = BRANCH_COLORS[colorIdx % BRANCH_COLORS.length]
      branchColorMap.set(branch, color)
      colorIdx++
    }
    return color
  }

  return (
    <div className="divide-y divide-gray-100">
      {commits.map((commit) => {
        const branch = getCommitBranch(commit.refs)
        const { branches, tags, isHead } = parseRefs(commit.refs)
        const isExpanded = expandedHash === commit.hash

        // Determine dot color
        const dotColor = branch ? getOrAssignColor(branch) : TREE_DEFAULTS.GRAY
        const dotStyle: 'filled' | 'outlined' | 'hollow' = isHead ? 'filled' : branch ? 'outlined' : 'hollow'

        // Build guides for the graph lane
        const guides: GuideEntry[] = [
          {
            type: 'dot',
            color: dotColor,
            dotStyle,
            hasLineBelow: true, // will be refined in Phase 2 with multi-lane
            lineBelowColor: TREE_DEFAULTS.GRAY,
          },
        ]

        return (
          <div key={commit.hash}>
            <div
              className="group flex items-center hover:bg-gray-100 cursor-pointer transition-colors"
              onClick={() => handleToggleCommit(commit.hash)}
            >
              <div className="flex-shrink-0">
                <TreeGraphRow guides={guides}>
                  <div className="flex-1 flex items-center gap-1.5 py-1.5 pr-2 min-w-0">
                    {/* Commit hash */}
                    <span className="font-mono text-[10px] text-gray-400 flex-shrink-0">{commit.shortHash}</span>

                    {/* Branch/tag badges */}
                    {branches.map(b => (
                      <span
                        key={b}
                        className="flex-shrink-0 px-1 py-0 rounded text-[10px] font-medium truncate max-w-[80px]"
                        style={{
                          backgroundColor: getOrAssignColor(b) + '18',
                          color: getOrAssignColor(b),
                        }}
                        title={b}
                      >
                        {b}
                      </span>
                    ))}
                    {tags.map(t => (
                      <span
                        key={t}
                        className="flex-shrink-0 px-1 py-0 rounded text-[10px] font-medium bg-amber-50 text-amber-600 truncate max-w-[80px]"
                        title={t}
                      >
                        {t}
                      </span>
                    ))}
                  </div>
                </TreeGraphRow>
              </div>
            </div>

            {/* Commit message + meta (below the hash/branch line) */}
            <div
              className="group flex items-center hover:bg-gray-100 cursor-pointer transition-colors"
              onClick={() => handleToggleCommit(commit.hash)}
            >
              {/* Left spacer matching the graph area */}
              <div className="flex-shrink-0" style={{ width: TREE_DEFAULTS.SLOT_W + 4 }} />

              <div className="flex-1 py-0.5 pr-2 min-w-0">
                <div className="text-gray-700 truncate">{commit.message}</div>
                <div className="text-[10px] text-gray-400 mt-0.5">
                  {commit.author_name} · {formatRelativeTime(commit.date)}
                </div>
              </div>

              {/* Expand/collapse indicator */}
              <div className="flex-shrink-0 px-2 text-gray-300">
                <svg
                  className={`w-3 h-3 transition-transform ${isExpanded ? 'rotate-90' : ''}`}
                  fill="currentColor"
                  viewBox="0 0 20 20"
                >
                  <path
                    fillRule="evenodd"
                    d="M7.21 14.77a.75.75 0 01.02-1.06L11.168 10 7.23 6.29a.75.75 0 111.04-1.08l4.5 4.25a.75.75 0 010 1.08l-4.5 4.25a.75.75 0 01-1.06-.02z"
                    clipRule="evenodd"
                  />
                </svg>
              </div>
            </div>

            {/* Expanded commit detail */}
            {isExpanded && (
              <CommitDetailInline
                hash={commit.hash}
                detail={expandedDetail}
                loading={detailLoading}
                onFileSelect={(filePath) => onCommitFileSelect?.(commit.hash, filePath)}
                onClose={() => {
                  setExpandedHash(null)
                  setExpandedDetail(null)
                }}
              />
            )}
          </div>
        )
      })}

      {/* Load more */}
      {hasMore && (
        <div className="px-3 py-2 text-center">
          <button
            onClick={handleLoadMore}
            disabled={loadingMore}
            className="text-xs text-blue-500 hover:text-blue-600 hover:underline disabled:text-gray-400 disabled:no-underline"
          >
            {loadingMore ? 'Loading...' : 'Load more'}
          </button>
        </div>
      )}
    </div>
  )
}

import type { CommitDetail, FileChange } from '../types/git'

function statusBadgeColor(status: string): string {
  switch (status) {
    case 'M': return 'bg-amber-50 text-amber-600'
    case 'A': return 'bg-green-50 text-green-600'
    case 'D': return 'bg-red-50 text-red-600'
    case 'R': return 'bg-blue-50 text-blue-600'
    case 'C': return 'bg-purple-50 text-purple-600'
    default: return 'bg-gray-50 text-gray-500'
  }
}

function statusBadgeLabel(status: string): string {
  switch (status) {
    case 'M': return 'M'
    case 'A': return 'A'
    case 'D': return 'D'
    case 'R': return 'R'
    case 'C': return 'C'
    default: return status
  }
}

function FileChangeItem({
  file,
  onFileSelect,
}: {
  file: FileChange
  onFileSelect: (filePath: string) => void
}) {
  return (
    <div
      className="flex items-center gap-1.5 py-0.5 px-2 hover:bg-gray-50 cursor-pointer rounded group"
      onClick={() => onFileSelect(file.path)}
      title={file.path}
    >
      <span className={`px-1 py-0 rounded text-[10px] font-mono font-semibold ${statusBadgeColor(file.status)}`}>
        {statusBadgeLabel(file.status)}
      </span>
      <span className="flex-1 truncate text-gray-600 group-hover:text-gray-900 transition-colors">
        {file.path}
      </span>
      <span className="text-[10px] text-gray-300 flex-shrink-0">
        {file.additions > 0 && <span className="text-green-500">+{file.additions}</span>}
        {file.additions > 0 && file.deletions > 0 && <span className="text-gray-300">/</span>}
        {file.deletions > 0 && <span className="text-red-400">-{file.deletions}</span>}
      </span>
      <svg
        className="w-3 h-3 text-gray-300 group-hover:text-gray-500 flex-shrink-0 transition-colors"
        fill="none"
        viewBox="0 0 24 24"
        stroke="currentColor"
        strokeWidth={2}
      >
        <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" />
      </svg>
    </div>
  )
}

export default function CommitDetailInline({
  hash,
  detail,
  loading,
  onFileSelect,
  onClose,
}: {
  hash: string
  detail: CommitDetail | null
  loading: boolean
  onFileSelect: (filePath: string) => void
  onClose: () => void
}) {
  return (
    <div className="border-t border-b border-gray-200 bg-gray-50/50">
      {/* Header with close button */}
      <div className="flex items-center justify-between px-3 pt-2 pb-1">
        <span className="font-mono text-[10px] text-gray-400">{hash}</span>
        <button
          onClick={(e) => {
            e.stopPropagation()
            onClose()
          }}
          className="rounded p-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-200 transition-colors"
          title="Close"
        >
          <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>

      {loading && (
        <div className="px-3 pb-2 text-gray-400 text-[10px]">Loading details...</div>
      )}

      {!loading && detail && (
        <div className="px-3 pb-2">
          {/* Full message */}
          {detail.body && (
            <div className="text-gray-500 text-[11px] mt-0.5 mb-1 whitespace-pre-wrap">
              {detail.body}
            </div>
          )}

          {/* Author & date */}
          <div className="text-[10px] text-gray-400 flex items-center gap-2 mb-2">
            <span>{detail.author_name}</span>
            {detail.author_email && (
              <span className="text-gray-300">&lt;{detail.author_email}&gt;</span>
            )}
            <span>·</span>
            <span>{new Date(detail.date).toLocaleString()}</span>
          </div>

          {/* Changed files */}
          {detail.files.length > 0 && (
            <div>
              <div className="text-[10px] text-gray-500 font-medium mb-1">
                Changed files ({detail.files.length})
              </div>
              <div className="space-y-0.5">
                {detail.files.map((file) => (
                  <FileChangeItem
                    key={file.path}
                    file={file}
                    onFileSelect={onFileSelect}
                  />
                ))}
              </div>
            </div>
          )}

          {detail.files.length === 0 && (
            <div className="text-[10px] text-gray-400">No file changes in this commit</div>
          )}
        </div>
      )}

      {!loading && !detail && (
        <div className="px-3 pb-2 text-gray-400 text-[10px]">Failed to load commit details</div>
      )}
    </div>
  )
}

